          <h3 className="font-semibold text-sm text-gray-800 mb-1 line-clamp-1 group-hover:text-[#F25D49] transition-colors">
            {product.proName}
          </h3>

          <div className="flex items-center mb-2">
            <div className="flex items-center">
              {[...Array(5)].map((_, i) => (
                <Star
                  key={i}
                  className={`w-3 h-3 ${
                    i < Math.floor(averageRating) ? 'text-yellow-400 fill-current' : 'text-gray-300'
                  }`}
                />
              ))}
            </div>
            <span className="text-xs text-gray-500 ml-1">
              ({product.reviews?.length || 0})
            </span>
          </div>

          <div className="flex items-center justify-between">
            <div>
              {product.salePrice && parseFloat(product.salePrice) < parseFloat(product.price) ? (
                <div className="flex items-center gap-2">
                  <span className="text-base font-bold text-[#F25D49]">
                    ${parseFloat(product.salePrice)}
                  </span>
                  <span className="text-xs text-gray-500 line-through">
                    ${parseFloat(product.price)}
                  </span>
                </div>
              ) : (
                <span className="text-base font-bold text-[#F25D49]">
                  ${parseFloat(product.price)}
                </span>
              )}
            </div>

            <div className="flex items-center gap-2">
              <motion.button
                onClick={(e) => {
                  e.stopPropagation()
                  addToCart(product)
                }}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                className="flex-1 px-3 py-1.5 bg-gradient-to-r from-[#F25D49] to-[#FF6B5B] text-white rounded-lg text-xs font-medium hover:from-[#F25D49]/90 hover:to-[#FF6B5B]/90 transition-all duration-300 flex items-center justify-center gap-1"
              >
                <ShoppingCart className="w-3 h-3" />
                <span>Add</span>
              </motion.button>

              <motion.button
                onClick={handleWishlistToggle}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                className={`px-2 py-1.5 rounded-lg text-xs font-medium transition-all duration-300 flex items-center justify-center ${
                  inWishlist 
                    ? 'bg-[#F25D49]/20 text-[#F25D49] border border-[#F25D49]/30' 
                    : 'bg-gray-100 text-gray-600 hover:bg-[#F25D49]/10 hover:text-[#F25D49]'
                }`}
                title={inWishlist ? 'Remove from Wishlist' : 'Add to Wishlist'}
              >
                <Heart className={`w-3 h-3 ${inWishlist ? 'fill-current' : ''}`} />
              </motion.button>
            </div>
          </div>
        </div>
      </motion.div>
    )
  }

  if (loading) {
    console.log('ProductCatalog loading...')
    return (
      <div className="flex items-center justify-center h-64">
        <LoadingSpinner size="lg" text="Loading products..." />
      </div>
    )
  }

  console.log('ProductCatalog products:', products.length)
  console.log('ProductCatalog categories:', categories.length)
  console.log('ProductCatalog products data:', products)
  console.log('ProductCatalog filtered products:', filteredProducts.length)
  console.log('ProductCatalog sorted products:', sortedProducts.length)

  return (
    <div className="w-full overflow-x-hidden">
      <div className="space-y-8">
